('university', 'UNILAG QS 302', 'Cost Planning', 'What is the primary purpose of cost planning?', 'mcq', '["To reduce contractor profit", "To control and predict project costs", "To increase material costs", "To eliminate professional fees"]'::jsonb, 'B', 'Cost planning aims to control and predict project costs throughout the project lifecycle.', 'easy', 2020, 'University of Lagos', 'QS 302'),
