('university', 'ABU QS 402', 'Cost Planning', 'Value engineering in cost planning aims to:', 'mcq', '["Reduce quality to cut costs", "Optimize cost while maintaining or improving value", "Increase project scope", "Eliminate professional fees"]'::jsonb, 'B', 'Value engineering optimizes cost while maintaining or improving functional value.', 'easy', 2022, 'Ahmadu Bello University', 'QS 402'),
