('university', 'UNIZIK QS 310', 'Professional Practice', 'Continuing professional development (CPD) means:', 'mcq', '["Initial qualification only", "Ongoing learning to maintain and update professional competence", "No further education needed", "Changing careers"]'::jsonb, 'B', 'CPD requires ongoing learning to maintain and update professional knowledge and skills.', 'easy', 2023, 'Nnamdi Azikiwe University', 'QS 310'),
