('university', 'LAUTECH QS 310', 'Professional Practice', 'A fee agreement between a QS and client should include:', 'mcq', '["Only the total fee", "Scope of services, fee basis, payment terms, and responsibilities", "Only the timeline", "Nothing in writing"]'::jsonb, 'B', 'Fee agreements should clearly define scope, fee basis, payment terms, and responsibilities.', 'medium', 2021, 'Ladoke Akintola University', 'QS 310'),
('university', 'AAU QS 310', 'Professional Practice', 'The Nigerian Institute of Quantity Surveyors (NIQS) is:', 'mcq', '["A government ministry", "A professional membership body for quantity surveyors", "A construction company", "A training school only"]'::jsonb, 'B', 'NIQS is the professional membership body for quantity surveyors in Nigeria.', 'easy', 2023, 'Ambrose Alli University', 'QS 310'),
('university', 'KSU QS 210', 'Professional Practice', 'A QS duty of confidentiality means:', 'mcq', '["Sharing all client information publicly", "Not disclosing client information without authorization", "Ignoring privacy rules", "Publishing project costs"]'::jsonb, 'B', 'A QS must maintain confidentiality of client information unless authorized to disclose.', 'easy', 2018, 'Kogi State University', 'QS 210'),
