('university', 'UNIJOS QS 310', 'Professional Practice', 'An expert witness in construction disputes is usually:', 'mcq', '["Any construction worker", "A qualified professional providing expert opinion to a tribunal", "The contractor only", "The client only"]'::jsonb, 'B', 'An expert witness is a qualified professional who provides expert opinion evidence.', 'medium', 2022, 'University of Jos', 'QS 310'),
('university', 'BUK QS 310', 'Professional Practice', 'The standard of care expected of a professional is that of:', 'mcq', '["A layperson", "A reasonably competent professional in the same field", "A perfectionist", "An amateur"]'::jsonb, 'B', 'The standard of care is that of a reasonably competent professional in the same field.', 'easy', 2021, 'Bayero University Kano', 'QS 310'),
('university', 'UNIPORT QS 310', 'Professional Practice', 'A QS role in value engineering is to:', 'mcq', '["Increase costs always", "Identify opportunities to reduce cost while maintaining quality", "Eliminate all specifications", "Reduce project scope"]'::jsonb, 'B', 'A QS identifies value engineering opportunities to optimize cost without sacrificing quality.', 'medium', 2019, 'University of Port Harcourt', 'QS 310'),
