('university', 'OAU QS 310', 'Professional Practice', 'A QS advising on life-cycle costing considers:', 'mcq', '["Only initial construction cost", "Total cost of ownership over the building entire life", "Only material costs", "Only labor costs"]'::jsonb, 'B', 'Life-cycle costing considers all costs from construction through operation to demolition.', 'medium', 2018, 'Obafemi Awolowo University', 'QS 310'),
('university', 'ABU QS 410', 'Professional Practice', 'The term due professional care means:', 'mcq', '["Working as fast as possible", "Applying the skill and care expected of a competent QS", "Ignoring standards", "Cutting corners"]'::jsonb, 'B', 'Due professional care requires applying the skill, knowledge, and care expected of a competent professional.', 'easy', 2022, 'Ahmadu Bello University', 'QS 410'),
('university', 'FUTA QS 310', 'Professional Practice', 'A QS duty to the public includes:', 'mcq', '["Serving only private clients", "Contributing to public welfare through professional competence", "Ignoring public interest", "Maximizing personal income"]'::jsonb, 'B', 'Professionals have a duty to serve the public welfare through competent practice.', 'easy', 2020, 'Federal University of Technology Akure', 'QS 310'),
('university', 'UNN QS 310', 'Professional Practice', 'Dispute avoidance in professional practice involves:', 'mcq', '["Ignoring potential conflicts", "Clear documentation, communication, and proactive risk management", "Escalating all issues to court", "Avoiding all client contact"]'::jsonb, 'B', 'Dispute avoidance uses clear documentation, communication, and proactive risk management.', 'medium', 2021, 'University of Nigeria Nsukka', 'QS 310'),
('university', 'CU QS 210', 'Professional Practice', 'A QS acting as project manager coordinates:', 'mcq', '["Only the design team", "Design, cost, time, and quality across the project", "Only the construction team", "Only the client"]'::jsonb, 'B', 'As project manager, the QS coordinates design, cost, time, and quality aspects.', 'medium', 2023, 'University of Calabar', 'QS 210'),
