('university', 'UNIZIK QS 310', 'Professional Practice', 'The role of a QS in sustainability includes:', 'mcq', '["Ignoring environmental impact", "Advising on sustainable materials and life-cycle environmental costs", "Only considering cost", "Only considering aesthetics"]'::jsonb, 'B', 'A QS advises on sustainable choices considering environmental impact and whole-life costs.', 'medium', 2020, 'Nnamdi Azikiwe University', 'QS 310'),
('university', 'FUTO QS 210', 'Professional Practice', 'A QS conflict of interest must be:', 'mcq', '["Ignored if minor", "Disclosed to all affected parties promptly", "Hidden from the client", "Accepted without disclosure"]'::jsonb, 'B', 'Any conflict of interest must be promptly disclosed to all affected parties.', 'easy', 2021, 'Federal University of Technology Owerri', 'QS 210'),
