('university', 'LAUTECH QS 311', 'Tendering', 'Late tenders are typically:', 'mcq', '["Accepted without penalty", "Rejected unless the delay was due to the clients fault", "Always accepted", "Never submitted"]'::jsonb, 'B', 'Late tenders are rejected unless the delay is attributable to the client.', 'easy', 2023, 'Ladoke Akintola University', 'QS 311'),
