('university', 'KSU QS 211', 'Tendering', 'A tender extension is granted when:', 'mcq', '["The contractor is late", "More time is needed for tender preparation due to client-side changes", "Construction is delayed", "Payment is overdue"]'::jsonb, 'B', 'Extensions are granted when client-side changes require additional tender preparation time.', 'medium', 2022, 'Kogi State University', 'QS 211'),
