('university', 'UNIJOS QS 311', 'Tendering', 'A tenderer may withdraw their tender:', 'mcq', '["At any time without consequence", "Before the deadline without penalty, or after with possible bond forfeiture", "Never", "Only after contract award"]'::jsonb, 'B', 'Withdrawal before deadline is usually permitted; after deadline may forfeit the tender bond.', 'hard', 2021, 'University of Jos', 'QS 311'),
('university', 'BUK QS 311', 'Tendering', 'A negotiation stage after tendering is used to:', 'mcq', '["Start construction", "Finalize contract terms and conditions with the preferred tenderer", "Dismiss all tenderers", "Cancel the project"]'::jsonb, 'B', 'Post-tender negotiation finalizes contract terms and conditions with the preferred tenderer.', 'medium', 2018, 'Bayero University Kano', 'QS 311'),
