('university', 'UNILAG QS 312', 'Estimate and Cost Control', 'The purpose of cost control during construction is to:', 'mcq', '["Increase costs", "Ensure the project is completed within the approved budget", "Reduce quality", "Eliminate professional fees"]'::jsonb, 'B', 'Cost control ensures the project stays within the approved budget throughout construction.', 'easy', 2020, 'University of Lagos', 'QS 312'),
('university', 'OAU QS 312', 'Estimate and Cost Control', 'An interim payment certificate is issued:', 'mcq', '["Only at project completion", "At regular intervals during construction for work done", "Before construction starts", "Only for variations"]'::jsonb, 'B', 'Interim certificates are issued at regular intervals for work completed in each period.', 'easy', 2019, 'Obafemi Awolowo University', 'QS 312'),
('university', 'ABU QS 412', 'Estimate and Cost Control', 'The cash flow forecast in cost control shows:', 'mcq', '["Past payments only", "Projected income and expenditure over the project period", "Only material costs", "Only labor costs"]'::jsonb, 'B', 'Cash flow forecasts show projected income and expenditure over the project timeline.', 'medium', 2021, 'Ahmadu Bello University', 'QS 412'),
('university', 'FUTA QS 312', 'Estimate and Cost Control', 'A cost report during construction communicates:', 'mcq', '["Site progress photos", "Current cost status compared to budget", "Worker attendance", "Weather conditions"]'::jsonb, 'B', 'Cost reports compare actual costs against budget and forecast to completion.', 'easy', 2018, 'Federal University of Technology Akure', 'QS 312'),
('university', 'UNN QS 312', 'Estimate and Cost Control', 'The final account in construction represents:', 'mcq', '["The tender sum", "The agreed final contract sum including all adjustments", "The initial estimate", "The insurance value"]'::jsonb, 'B', 'The final account is the agreed sum after incorporating all variations and adjustments.', 'medium', 2022, 'University of Nigeria Nsukka', 'QS 312'),
('university', 'CU QS 212', 'Estimate and Cost Control', 'Cost escalation during construction can be caused by:', 'mcq', '["Good project management", "Inflation, design changes, and unforeseen conditions", "Efficient material use", "Proper planning"]'::jsonb, 'B', 'Cost escalation results from inflation, design changes, delays, and unforeseen conditions.', 'easy', 2020, 'University of Calabar', 'QS 212'),
