('university', 'FUTMINNA QS 312', 'Estimate and Cost Control', 'A contingency allowance is used for:', 'mcq', '["Known costs only", "Unforeseen or unforeseeable items not in the original estimate", "Contractor profit", "Professional fees"]'::jsonb, 'B', 'Contingency allowances cover unforeseen items not included in the original estimate.', 'medium', 2019, 'Federal University of Technology Minna', 'QS 312'),
('university', 'UNIBEN QS 312', 'Estimate and Cost Control', 'A cost estimate prepared at the feasibility stage is typically:', 'mcq', '["Very accurate", "Approximate with a wider margin of error", "Final and binding", "Detailed to the last item"]'::jsonb, 'B', 'Feasibility estimates are approximate with a wider margin of error compared to detailed estimates.', 'medium', 2020, 'University of Benin', 'QS 312'),
('university', 'UNIZIK QS 312', 'Estimate and Cost Control', 'The purpose of a cost plan during design is to:', 'mcq', '["Set the contractor price", "Control design costs against the approved budget", "Measure completed work", "Calculate profit margins"]'::jsonb, 'B', 'Cost plans during design control costs against the approved budget at each stage.', 'easy', 2023, 'Nnamdi Azikiwe University', 'QS 312'),
('university', 'FUTO QS 212', 'Estimate and Cost Control', 'Cost variance in cost control is the difference between:', 'mcq', '["Design and construction", "Budgeted cost and actual cost", "Material prices", "Labor rates"]'::jsonb, 'B', 'Cost variance measures the difference between budgeted and actual costs.', 'easy', 2022, 'Federal University of Technology Owerri', 'QS 212'),
('university', 'LAUTECH QS 312', 'Estimate and Cost Control', 'The purpose of a cost estimate at the tender stage is to:', 'mcq', '["Start construction", "Determine a realistic price for the works", "Complete the design", "Select materials"]'::jsonb, 'B', 'Tender stage estimates determine a realistic and competitive price for the works.', 'easy', 2021, 'Ladoke Akintola University', 'QS 312'),
('university', 'AAU QS 312', 'Estimate and Cost Control', 'Cost monitoring during construction involves:', 'mcq', '["Ignoring costs", "Regular comparison of actual costs against the budget", "Only checking material prices", "Only checking labor rates"]'::jsonb, 'B', 'Cost monitoring involves regular comparison of actual expenditure against the approved budget.', 'medium', 2023, 'Ambrose Alli University', 'QS 312'),
('university', 'KSU QS 212', 'Estimate and Cost Control', 'The preliminaries estimate covers:', 'mcq', '["Only material costs", "Site establishment, supervision, and general project costs", "Only contractor profit", "Only design fees"]'::jsonb, 'B', 'Preliminaries estimate covers site overheads, supervision, insurance, and general costs.', 'medium', 2018, 'Kogi State University', 'QS 212'),
('university', 'IMSU QS 312', 'Estimate and Cost Control', 'An estimate for cost control purposes should be:', 'mcq', '["As high as possible", "Realistic and based on available information", "As low as possible always", "Ignore market conditions"]'::jsonb, 'B', 'Estimates should be realistic and based on current market conditions and available information.', 'easy', 2020, 'Imo State University', 'QS 312'),
('university', 'UNIJOS QS 312', 'Estimate and Cost Control', 'A cost estimate for a variation is prepared to:', 'mcq', '["Ignore the variation", "Determine the cost impact of the proposed change", "Cancel the contract", "Increase the contractor profit"]'::jsonb, 'B', 'Variation estimates determine the cost impact of proposed changes to the original scope.', 'medium', 2022, 'University of Jos', 'QS 312'),
