('university', 'UNIPORT QS 312', 'Estimate and Cost Control', 'The purpose of a cost plan update is to:', 'mcq', '["Ignore changes", "Reflect current cost position and adjusted forecast", "Increase the budget", "Reduce the scope"]'::jsonb, 'B', 'Cost plan updates reflect the current cost position and adjusted forecast to completion.', 'medium', 2019, 'University of Port Harcourt', 'QS 312'),
('university', 'UNILAG QS 312', 'Estimate and Cost Control', 'A detailed estimate is prepared using:', 'mcq', '["Approximate methods only", "Measured quantities from drawings and priced rates", "Guesswork", "Only historical data"]'::jsonb, 'B', 'Detailed estimates use measured quantities from drawings combined with priced rates.', 'easy', 2023, 'University of Lagos', 'QS 312'),
('university', 'OAU QS 312', 'Estimate and Cost Control', 'Cost performance index (CPI) measures:', 'mcq', '["Quality of work", "Efficiency of cost utilization on the project", "Time performance", "Material quality"]'::jsonb, 'B', 'CPI measures the cost efficiency of work completed versus the budgeted cost.', 'hard', 2018, 'Obafemi Awolowo University', 'QS 312'),
('university', 'ABU QS 412', 'Estimate and Cost Control', 'An estimate contingency is based on:', 'mcq', '["A fixed percentage always", "Assessment of risks and probability of unforeseen items", "Contractor preference", "Government regulations only"]'::jsonb, 'B', 'Contingency is based on risk assessment and probability of unforeseen events.', 'medium', 2022, 'Ahmadu Bello University', 'QS 412'),
('university', 'FUTA QS 312', 'Estimate and Cost Control', 'A cost estimate for insurance purposes determines:', 'mcq', '["Contractor profit", "The replacement cost for insuring the works", "Material prices", "Labor rates"]'::jsonb, 'B', 'Insurance estimates determine the replacement cost for adequate insurance coverage.', 'medium', 2020, 'Federal University of Technology Akure', 'QS 312'),
('university', 'UNN QS 312', 'Estimate and Cost Control', 'Cost control requires regular:', 'mcq', '["Site inspections only", "Reporting, analysis, and corrective action on cost deviations", "Material testing", "Worker supervision only"]'::jsonb, 'B', 'Cost control requires regular reporting, analysis, and corrective action on deviations.', 'medium', 2021, 'University of Nigeria Nsukka', 'QS 312'),
('university', 'CU QS 212', 'Estimate and Cost Control', 'The purpose of a bill of abstract is to:', 'mcq', '["Measure quantities only", "Summarize contractor priced rates from the bill of quantities", "Design the building", "Plan the construction"]'::jsonb, 'B', 'The abstract summarizes the contractor priced rates to determine the tender sum.', 'easy', 2023, 'University of Calabar', 'QS 212'),
