('university', 'FUTMINNA QS 312', 'Estimate and Cost Control', 'A cost estimate at the concept stage is called a:', 'mcq', '["Detailed estimate", "Feasibility or approximate estimate", "Final account", "Variation order"]'::jsonb, 'B', 'Concept stage estimates are feasibility or approximate estimates for initial budgeting.', 'easy', 2022, 'Federal University of Technology Minna', 'QS 312'),
('university', 'UNIBEN QS 312', 'Estimate and Cost Control', 'The purpose of a value engineering study is to:', 'mcq', '["Increase costs", "Optimize value by reducing cost or improving function", "Reduce quality only", "Eliminate specifications"]'::jsonb, 'B', 'Value engineering optimizes value by reducing unnecessary cost while maintaining or improving function.', 'medium', 2018, 'University of Benin', 'QS 312'),
