('university', 'AAU QS 313', 'Construction Law', 'The term privity of contract means:', 'mcq', '["Open to all parties", "Only parties to a contract can enforce its terms", "The contract is public", "No contract exists"]'::jsonb, 'B', 'Privity of contract means only parties to a contract can enforce its terms.', 'medium', 2023, 'Ambrose Alli University', 'QS 313'),
