('university', 'UNIJOS QS 313', 'Construction Law', 'The term retention in construction law refers to:', 'mcq', '["A type of insurance", "Money withheld from payments as security for defect rectification", "A type of variation", "A payment method"]'::jsonb, 'B', 'Retention is money withheld as security for rectifying defects during the defects period.', 'easy', 2022, 'University of Jos', 'QS 313'),
('university', 'BUK QS 313', 'Construction Law', 'A collateral warranty in construction provides:', 'mcq', '["Primary contract rights", "Direct contractual rights to third parties", "Insurance coverage", "Design services"]'::jsonb, 'B', 'Collateral warranties give third parties direct contractual rights against professionals or contractors.', 'medium', 2021, 'Bayero University Kano', 'QS 313'),
('university', 'UNIPORT QS 313', 'Construction Law', 'The term quantum meruit means:', 'mcq', '["Fixed contract price", "Payment for the reasonable value of work done", "No payment required", "Maximum payment"]'::jsonb, 'B', 'Quantum meruit means payment for the reasonable value of work actually performed.', 'medium', 2019, 'University of Port Harcourt', 'QS 313'),
('university', 'UNILAG QS 313', 'Construction Law', 'The standard of proof in civil construction claims is:', 'mcq', '["Beyond reasonable doubt", "On the balance of probabilities", "Absolute certainty", "No proof needed"]'::jsonb, 'B', 'Civil claims are proved on the balance of probabilities, not beyond reasonable doubt.', 'easy', 2023, 'University of Lagos', 'QS 313'),
('university', 'OAU QS 313', 'Construction Law', 'The duty to mitigate in construction disputes means:', 'mcq', '["Maximize losses", "Take reasonable steps to minimize losses suffered", "Ignore losses", "Increase costs"]'::jsonb, 'B', 'The duty to mitigate requires taking reasonable steps to minimize losses.', 'medium', 2018, 'Obafemi Awolowo University', 'QS 313'),
('university', 'ABU QS 413', 'Construction Law', 'The term defect liability period allows:', 'mcq', '["No defects to be rectified", "The employer to require the contractor to rectify identified defects", "The contractor to leave defects", "Ignoring all defects"]'::jsonb, 'B', 'During the DLP, the contractor is obligated to rectify identified defects.', 'easy', 2022, 'Ahmadu Bello University', 'QS 413'),
('university', 'FUTA QS 313', 'Construction Law', 'The term estoppel in construction law means:', 'mcq', '["A type of insurance", "A party is prevented from denying what they previously represented", "A type of variation", "A payment method"]'::jsonb, 'B', 'Estoppel prevents a party from denying facts they previously represented as true.', 'hard', 2020, 'Federal University of Technology Akure', 'QS 313'),
('university', 'UNN QS 313', 'Construction Law', 'The employer right to terminate for convenience means:', 'mcq', '["The contractor can terminate", "The employer can terminate without cause by following proper procedures", "No termination is possible", "Only the court can terminate"]'::jsonb, 'B', 'The employer may terminate for convenience by following contractual procedures.', 'medium', 2021, 'University of Nigeria Nsukka', 'QS 313'),
('university', 'CU QS 213', 'Construction Law', 'The term indemnity in construction contracts means:', 'mcq', '["A type of variation", "An obligation to compensate for loss or damage suffered", "A payment method", "A design requirement"]'::jsonb, 'B', 'Indemnity is an obligation to compensate for loss or damage suffered by another party.', 'medium', 2023, 'University of Calabar', 'QS 213'),
('university', 'UI QS 413', 'Construction Law', 'The building law requires that certain works be carried out by:', 'mcq', '["Any person", "Registered and licensed professionals and contractors", "Only government officials", "Only the client"]'::jsonb, 'B', 'Building laws require works to be carried out by registered and licensed professionals.', 'easy', 2019, 'University of Ibadan', 'QS 413'),
('university', 'FUTMINNA QS 313', 'Construction Law', 'The term implied term in construction law means:', 'mcq', '["A term written in the contract", "A term automatically included by law even if not written", "An optional term", "A term that can be ignored"]'::jsonb, 'B', 'Implied terms are automatically included by law or custom even if not expressly stated.', 'medium', 2022, 'Federal University of Technology Minna', 'QS 313'),
('university', 'UNIBEN QS 313', 'Construction Law', 'The legal effect of a signed contract is that:', 'mcq', '["It can be ignored", "The parties are legally bound by its terms", "Only some terms apply", "It has no legal effect"]'::jsonb, 'B', 'A signed contract creates legally binding obligations on all parties.', 'easy', 2018, 'University of Benin', 'QS 313'),
('university', 'UNIZIK QS 313', 'Construction Law', 'The term novation in construction law allows:', 'mcq', '["Canceling the contract", "Substituting a new party or contract for the existing one", "Ignoring the contract", "Starting construction"]'::jsonb, 'B', 'Novation substitutes a new party or contract while discharging the original obligation.', 'medium', 2020, 'Nnamdi Azikiwe University', 'QS 313'),
('university', 'FUTO QS 213', 'Construction Law', 'The parol evidence rule in construction law means:', 'mcq', '["All evidence is admissible", "Extrinsic evidence cannot vary the terms of a written contract", "No evidence is needed", "Only oral evidence is admissible"]'::jsonb, 'B', 'The parol evidence rule prevents introducing evidence to vary the terms of a written contract.', 'hard', 2021, 'Federal University of Technology Owerri', 'QS 213'),
('university', 'LAUTECH QS 313', 'Construction Law', 'The term lien in construction law refers to:', 'mcq', '["A type of insurance", "A right to retain property until a debt is paid", "A type of variation", "A payment method"]'::jsonb, 'B', 'A lien is a right to retain property until a debt or obligation is satisfied.', 'medium', 2023, 'Ladoke Akintola University', 'QS 313'),
('university', 'AAU QS 313', 'Construction Law', 'The standard of professional care expected of a QS is:', 'mcq', '["No standard applies", "That of a reasonably competent quantity surveyor", "Perfection is required", "The lowest standard possible"]'::jsonb, 'B', 'The standard is that of a reasonably competent quantity surveyor in the same circumstances.', 'easy', 2019, 'Ambrose Alli University', 'QS 313'),
('university', 'KSU QS 213', 'Construction Law', 'A repudiatory breach in construction law means:', 'mcq', '["A minor breach", "A breach so serious it entitles the innocent party to terminate", "A breach that can be ignored", "A breach that only affects price"]'::jsonb, 'B', 'A repudiatory breach is sufficiently serious to entitle the innocent party to terminate.', 'medium', 2022, 'Kogi State University', 'QS 213'),
('university', 'IMSU QS 313', 'Construction Law', 'The term consideration in contract law means:', 'mcq', '["Nothing is required", "Something of value exchanged between the parties", "Only the price", "Only the design"]'::jsonb, 'B', 'Consideration is something of value exchanged between parties to form a valid contract.', 'medium', 2020, 'Imo State University', 'QS 313'),
('university', 'UNIJOS QS 313', 'Construction Law', 'The term negligence in construction means:', 'mcq', '["Working carefully", "Failure to exercise reasonable care resulting in loss or damage", "Following instructions", "Completing work on time"]'::jsonb, 'B', 'Negligence is the failure to exercise reasonable care, resulting in foreseeable loss or damage.', 'easy', 2021, 'University of Jos', 'QS 313'),
('university', 'BUK QS 313', 'Construction Law', 'The term damages in construction law refers to:', 'mcq', '["Physical damage to the building", "Monetary compensation for breach of contract", "Material defects", "Worker injuries"]'::jsonb, 'B', 'Damages in construction law refer to monetary compensation for breach of contract.', 'easy', 2018, 'Bayero University Kano', 'QS 313'),
('university', 'UNIPORT QS 313', 'Construction Law', 'The term caveat emptor in construction means:', 'mcq', '["The seller guarantees everything", "The buyer assumes risk and should inspect before purchasing", "The contractor guarantees all work", "The employer assumes no risk"]'::jsonb, 'B', 'Caveat emptor means the buyer should inspect and assume risk in transactions.', 'medium', 2023, 'University of Port Harcourt', 'QS 313'),

