-- ═══════════════════════════════════════════════════════════════

('university', 'UNILAG QS 314', 'Project Management', 'The primary objective of project management is to:', 'mcq', '["Maximize costs", "Deliver the project within scope, time, and budget", "Ignore quality", "Avoid contracts"]'::jsonb, 'B', 'Project management aims to deliver projects within scope, time, cost, and quality requirements.', 'easy', 2020, 'University of Lagos', 'QS 314'),
('university', 'OAU QS 314', 'Project Management', 'The critical path in project scheduling is:', 'mcq', '["The shortest path", "The longest sequence of activities determining project duration", "Any path through the network", "The path with most resources"]'::jsonb, 'B', 'The critical path is the longest path through the network, determining the shortest project duration.', 'medium', 2019, 'Obafemi Awolowo University', 'QS 314'),
('university', 'ABU QS 414', 'Project Management', 'A Gantt chart in project management shows:', 'mcq', '["Only costs", "The project schedule with activities plotted against time", "Only resources", "Only quality parameters"]'::jsonb, 'B', 'A Gantt chart displays project activities as bars against a time scale.', 'easy', 2021, 'Ahmadu Bello University', 'QS 414'),
('university', 'FUTA QS 314', 'Project Management', 'The purpose of a project risk register is to:', 'mcq', '["Ignore risks", "Identify, assess, and manage project risks", "Track only material costs", "Plan worker shifts"]'::jsonb, 'B', 'A risk register identifies, assesses, and documents mitigation strategies for project risks.', 'easy', 2018, 'Federal University of Technology Akure', 'QS 314'),
('university', 'UNN QS 314', 'Project Management', 'Float or slack in project scheduling means:', 'mcq', '["No time available", "The amount of time an activity can be delayed without delaying the project", "The project is delayed", "The activity is critical"]'::jsonb, 'B', 'Float is the amount of time an activity can be delayed without affecting the project end date.', 'medium', 2022, 'University of Nigeria Nsukka', 'QS 314'),
('university', 'CU QS 214', 'Project Management', 'The project life cycle includes:', 'mcq', '["Only construction", "Initiation, planning, execution, monitoring, and closure", "Only design", "Only handover"]'::jsonb, 'B', 'The project life cycle spans from initiation through planning, execution, monitoring, to closure.', 'easy', 2020, 'University of Calabar', 'QS 214'),
('university', 'UI QS 414', 'Project Management', 'A work breakdown structure (WBS) organizes:', 'mcq', '["Only the budget", "Project deliverables into smaller, manageable components", "Only the schedule", "Only the team"]'::jsonb, 'B', 'A WBS breaks down project deliverables into smaller, more manageable components.', 'medium', 2021, 'University of Ibadan', 'QS 414'),
('university', 'FUTMINNA QS 314', 'Project Management', 'Earned value management measures:', 'mcq', '["Only costs", "Project performance by integrating scope, schedule, and cost", "Only time", "Only quality"]'::jsonb, 'B', 'EVM integrates scope, schedule, and cost to measure overall project performance.', 'medium', 2019, 'Federal University of Technology Minna', 'QS 314'),
('university', 'UNIBEN QS 314', 'Project Management', 'A project stakeholder is:', 'mcq', '["Only the contractor", "Anyone with an interest in or affected by the project", "Only the client", "Only the QS"]'::jsonb, 'B', 'Stakeholders include anyone affected by or with an interest in the project.', 'easy', 2020, 'University of Benin', 'QS 314'),
('university', 'UNIZIK QS 314', 'Project Management', 'The purpose of a project kick-off meeting is to:', 'mcq', '["End the project", "Align the team on objectives, scope, and responsibilities", "Start construction only", "Dismiss the team"]'::jsonb, 'B', 'The kick-off meeting aligns the team on project objectives, scope, roles, and responsibilities.', 'easy', 2023, 'Nnamdi Azikiwe University', 'QS 314'),
('university', 'FUTO QS 214', 'Project Management', 'The term scope creep in project management means:', 'mcq', '["The project is on schedule", "Uncontrolled expansion of project scope without adjustment to time and cost", "The project is under budget", "The project is complete"]'::jsonb, 'B', 'Scope creep is uncontrolled expansion of scope without corresponding adjustments to time and cost.', 'medium', 2022, 'Federal University of Technology Owerri', 'QS 214'),
('university', 'LAUTECH QS 314', 'Project Management', 'The RACI matrix in project management defines:', 'mcq', '["Only costs", "Roles and responsibilities: Responsible, Accountable, Consulted, Informed", "Only the schedule", "Only the risk"]'::jsonb, 'B', 'The RACI matrix defines who is Responsible, Accountable, Consulted, and Informed for each task.', 'medium', 2021, 'Ladoke Akintola University', 'QS 314'),
('university', 'AAU QS 314', 'Project Management', 'A project baseline is:', 'mcq', '["A suggestion", "The approved plan against which project performance is measured", "The final cost", "The initial estimate only"]'::jsonb, 'B', 'The baseline is the approved plan used as a reference point for measuring performance.', 'easy', 2023, 'Ambrose Alli University', 'QS 314'),
('university', 'KSU QS 214', 'Project Management', 'The critical path method (CPM) is used to:', 'mcq', '["Calculate costs only", "Determine the minimum project duration and critical activities", "Plan only resources", "Estimate only materials"]'::jsonb, 'B', 'CPM identifies the critical path and minimum duration for completing a project.', 'medium', 2018, 'Kogi State University', 'QS 214'),
('university', 'IMSU QS 314', 'Project Management', 'A project risk response strategy can include:', 'mcq', '["Ignoring risks", "Avoidance, mitigation, transfer, or acceptance of risks", "Only avoiding risks", "Only transferring risks"]'::jsonb, 'B', 'Risk responses include avoidance, mitigation, transfer, or acceptance strategies.', 'medium', 2020, 'Imo State University', 'QS 314'),
('university', 'UNIJOS QS 314', 'Project Management', 'The purpose of project monitoring and control is to:', 'mcq', '["Start the project", "Track progress against the plan and take corrective action", "End the project", "Dismiss the team"]'::jsonb, 'B', 'Monitoring and control tracks progress and takes corrective action to stay on plan.', 'easy', 2022, 'University of Jos', 'QS 314'),
('university', 'BUK QS 314', 'Project Management', 'A change control process in project management:', 'mcq', '["Ignores all changes", "Manages changes through evaluation, approval, and documentation", "Allows any change without approval", "Only allows cost increases"]'::jsonb, 'B', 'Change control evaluates, approves, and documents all changes to project scope, time, or cost.', 'medium', 2021, 'Bayero University Kano', 'QS 314'),
('university', 'UNIPORT QS 314', 'Project Management', 'The project close-out phase includes:', 'mcq', '["Starting construction", "Handover, final documentation, and lessons learned", "Design development", "Tender preparation"]'::jsonb, 'B', 'Close-out includes handover, final documentation, demobilization, and lessons learned.', 'easy', 2019, 'University of Port Harcourt', 'QS 314'),
('university', 'UNILAG QS 314', 'Project Management', 'A project communication plan ensures:', 'mcq', '["No communication is needed", "Information is shared with the right people at the right time", "Only emails are sent", "Only verbal updates"]'::jsonb, 'B', 'A communication plan ensures timely and appropriate information sharing with stakeholders.', 'medium', 2023, 'University of Lagos', 'QS 314'),
('university', 'OAU QS 314', 'Project Management', 'The term lean construction aims to:', 'mcq', '["Increase waste", "Maximize value while minimizing waste throughout the project", "Reduce quality", "Ignore client needs"]'::jsonb, 'B', 'Lean construction maximizes value while minimizing waste in all project processes.', 'medium', 2018, 'Obafemi Awolowo University', 'QS 314'),
('university', 'ABU QS 414', 'Project Management', 'A project quality plan defines:', 'mcq', '["Only the cost", "Quality standards, procedures, and responsibilities for the project", "Only the schedule", "Only the risk"]'::jsonb, 'B', 'A quality plan defines quality standards, procedures, and responsibilities.', 'easy', 2022, 'Ahmadu Bello University', 'QS 414'),
('university', 'FUTA QS 314', 'Project Management', 'The term milestone in project management means:', 'mcq', '["A small task", "A significant point or event in the project timeline", "The project start", "The project end only"]'::jsonb, 'B', 'A milestone is a significant point or event marking progress in the project.', 'easy', 2020, 'Federal University of Technology Akure', 'QS 314'),
('university', 'UNN QS 314', 'Project Management', 'The purpose of a project resource plan is to:', 'mcq', '["Ignore resources", "Ensure the right resources are available when needed", "Only plan costs", "Only plan time"]'::jsonb, 'B', 'A resource plan ensures people, equipment, and materials are available when required.', 'medium', 2021, 'University of Nigeria Nsukka', 'QS 314'),
('university', 'CU QS 214', 'Project Management', 'The term concurrent engineering in construction means:', 'mcq', '["Doing everything sequentially", "Overlapping design and construction phases", "Only doing design", "Only doing construction"]'::jsonb, 'B', 'Concurrent engineering overlaps design and construction phases to reduce project duration.', 'medium', 2023, 'University of Calabar', 'QS 214'),
('university', 'UI QS 414', 'Project Management', 'The purpose of a lessons learned register is to:', 'mcq', '["Ignore past experience", "Document what went well and what to improve for future projects", "Only record failures", "Only record successes"]'::jsonb, 'B', 'A lessons learned register documents successes and areas for improvement for future projects.', 'easy', 2019, 'University of Ibadan', 'QS 414'),
('university', 'FUTMINNA QS 314', 'Project Management', 'The term schedule compression in project management includes:', 'mcq', '["Extending the schedule", "Crashing or fast-tracking to reduce project duration", "Ignoring the schedule", "Only adding resources"]'::jsonb, 'B', 'Schedule compression includes crashing (adding resources) or fast-tracking (overlapping activities).', 'medium', 2022, 'Federal University of Technology Minna', 'QS 314'),
('university', 'UNIBEN QS 314', 'Project Management', 'A project governance framework ensures:', 'mcq', '["No oversight", "Clear decision-making authority and accountability", "Only financial control", "Only time control"]'::jsonb, 'B', 'Governance ensures clear decision-making authority, accountability, and oversight.', 'medium', 2018, 'University of Benin', 'QS 314'),
('university', 'UNIZIK QS 314', 'Project Management', 'The purpose of a project close-out report is to:', 'mcq', '["Start a new project", "Summarize project performance, outcomes, and lessons learned", "Continue construction", "Dismiss all contractors"]'::jsonb, 'B', 'A close-out report summarizes project performance, outcomes, and lessons for future reference.', 'easy', 2020, 'Nnamdi Azikiwe University', 'QS 314'),
('university', 'FUTO QS 214', 'Project Management', 'A project procurement plan identifies:', 'mcq', '["Only material sources", "What to procure, when, and from whom", "Only the schedule", "Only the cost"]'::jsonb, 'B', 'A procurement plan identifies what is needed, the timing, and sourcing strategy.', 'medium', 2021, 'Federal University of Technology Owerri', 'QS 214'),
('university', 'LAUTECH QS 314', 'Project Management', 'The term integrated project delivery means:', 'mcq', '["Each party works independently", "All parties collaborate throughout the project lifecycle", "Only the contractor manages", "Only the client manages"]'::jsonb, 'B', 'IPD brings all parties together to collaborate throughout the entire project lifecycle.', 'medium', 2023, 'Ladoke Akintola University', 'QS 314'),
('university', 'AAU QS 314', 'Project Management', 'The purpose of a project dashboard is to:', 'mcq', '["Hide information", "Provide a visual summary of key project metrics and status", "Only show costs", "Only show time"]'::jsonb, 'B', 'A dashboard provides a visual summary of key metrics including cost, time, quality, and risk.', 'easy', 2019, 'Ambrose Alli University', 'QS 314'),
('university', 'KSU QS 214', 'Project Management', 'The term agile project management is:', 'mcq', '["Rigid and sequential", "An iterative approach that adapts to changing requirements", "Only for software projects", "Only for large projects"]'::jsonb, 'B', 'Agile is an iterative approach that adapts to changing requirements throughout the project.', 'medium', 2022, 'Kogi State University', 'QS 214'),
('university', 'IMSU QS 314', 'Project Management', 'The purpose of stakeholder engagement is to:', 'mcq', '["Ignore stakeholders", "Ensure stakeholder needs and expectations are managed effectively", "Only inform the client", "Only inform the contractor"]'::jsonb, 'B', 'Stakeholder engagement identifies and manages stakeholder needs and expectations.', 'easy', 2020, 'Imo State University', 'QS 314'),
('university', 'UNIJOS QS 314', 'Project Management', 'A project risk register should be:', 'mcq', '["Created once and ignored", "Regularly reviewed and updated throughout the project", "Only filled at the end", "Only reviewed at the start"]'::jsonb, 'B', 'Risk registers must be regularly reviewed and updated throughout the project lifecycle.', 'medium', 2021, 'University of Jos', 'QS 314'),
('university', 'BUK QS 314', 'Project Management', 'The term earned value (EV) in project management represents:', 'mcq', '["Actual cost spent", "The budgeted cost of work actually completed", "The planned cost", "The remaining cost"]'::jsonb, 'B', 'Earned value represents the budgeted cost of work actually completed at a given point.', 'medium', 2018, 'Bayero University Kano', 'QS 314'),
('university', 'UNIPORT QS 314', 'Project Management', 'The purpose of project procurement management is to:', 'mcq', '["Ignore external resources", "Acquire goods and services from outside the project team effectively", "Only buy materials", "Only hire labor"]'::jsonb, 'B', 'Procurement management acquires external goods and services effectively and efficiently.', 'easy', 2023, 'University of Port Harcourt', 'QS 314'),

