('university', 'UNIZIK QS 315', 'Real Estate', 'The term valuation date in real estate is:', 'mcq', '["The date of construction", "The specific date on which the property value is determined", "The sale date", "The lease start date"]'::jsonb, 'B', 'The valuation date is the specific date on which the property value assessment is made.', 'medium', 2020, 'Nnamdi Azikiwe University', 'QS 315'),
